INSERT INTO `data_cotizacions` VALUES (5,'BKY500010B05','Cygnus Ray ZR',2024,'NEG','Midnight Black','MOTOCICLETA LCG125 CYGNUS RAYZR','MC','ATRÉVETE A SER DISTINTO','Con un diseño deportivo, urbano y dinámico la nueva CYGNUS RayZR expresa actitud por donde la veas. Disfruta la sensación de libertad que te brinda su motor de 4 tiempos, SOHC de 2 válvulas de 125 cc “BLUE CORE”, con transmisión continua variable y un peso ultra ligero de apenas 99 kilogramos, además ahorra como nunca lo imaginaste gracias al sistema Start&Stop que tiene incorporado. Además cuentas con una excelente capacidad de carga de 21 litros debajo del asiento.','Matt Light Blue','Matt Light Red','Midnight Black','Motor 125 cc con sistema blue core','Sistema start & stop','Sistema de frenado UBS','Tablero digital','Refrigerado por aire, 4 tiempos SOHC, 2 válvulas','125 cc','8 HP a 6,500 rpm','9.7 N-m a 5000 rpm','Eléctrico y patada','Automático CVT','Inyección electrónica, BlueCore','5.2 Litros','760 mm','113 kg','Horquillas telescópicas','Mono amortiguador trasero','Disco','Tambor','90/90-R12','110/90-R10',2069,'SCOOTER','SCOOTER',5,22,'CYGNUS_RAY_ZR/Logo/logocygnus_ray_zr.png','CYGNUS_RAY_ZR/cygnus_ray_zr_2024/moto/BKY500010B05.png','CYGNUS_RAY_ZR/cygnus_ray_zr_2024/estilo/estilo1.png','CYGNUS_RAY_ZR/cygnus_ray_zr_2024/estilo/estilo2.png','CYGNUS_RAY_ZR/cygnus_ray_zr_2024/estilo/estilo3.png','CYGNUS_RAY_ZR/cygnus_ray_zr_2024/beneficios/beneficio1.jpg','CYGNUS_RAY_ZR/cygnus_ray_zr_2024/beneficios/beneficio2.jpg','CYGNUS_RAY_ZR/cygnus_ray_zr_2024/beneficios/beneficio3.jpg','CYGNUS_RAY_ZR/cygnus_ray_zr_2024/beneficios/beneficio4.jpg',1,0,'2024-07-01 17:51:45','2024-07-01 17:51:45',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,1),(6,'BKY500010F16','Cygnus Ray ZR',2024,'AZU_MAT','Matt Light Blue','MOTOCICLETA LCG125 CYGNUS RAYZR','MC','ATRÉVETE A SER DISTINTO','Con un diseño deportivo, urbano y dinámico la nueva CYGNUS RayZR expresa actitud por donde la veas. Disfruta la sensación 