DROP TABLE IF EXISTS `items`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `items` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `codigo` char(50) DEFAULT NULL,
  `descripcion` text,
  `talla` char(50) DEFAULT NULL,
  `tipo_item_id` int NOT NULL,
  `precio` double DEFAULT NULL,
  `stock` int DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `activo` tinyint DEFAULT NULL,
  `borrado` tinyint DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `fk_tipo_item_idx` (`tipo_item_id`),
  CONSTRAINT `fk_tipo_item` FOREIGN KEY (`tipo_item_id`) REFERENCES `tipo_item` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=819 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
