INSERT INTO `maestro_modelos` VALUES (74,'BX5800010A06','XTZ125',2024,'TODO TERRENO','ON-OFF 0-149','AZU','Competition Blue','MOTOCICLETA XTZ125E XTZ125','MC','Supera tus límites','Su diseño, resistencia y maniobrabilidad convierten a la XTZ125 en una gran opción para usarla en todo tipo de caminos. Preparada para movilizarte ágilmente por la ciudad como para recorrer con mayor confort los terrenos difíciles, gracias a su suspensión trasera monocross. A la vez sus gráficos y colores le dan una apariencia más deportiva.','Competition Blue','Cross Black','Cross White','Diseño estilo motocross','Motor eficiente y de buen rendimiento','Freno de disco delantero equipado de serie, sumado a la suspensión monoshock trasera, brinda estabilidad y control','Aro delantero 21 Aro posterior 18','4 tiempos SOHC, enfriado por aire, monocilíndrico','124 cc','10 HP a 7,500 rpm','9.90 N-m a 5500 rpm','Eléctrico y patada','5 velocidades, engrane constante, cadena','Carburador','11 Litros','840 mm','118 kg','Horquilla telescópica','Basculante (Monocross)','Disco','Tambor','80/90-R21','110/80-R18',2599,0,2599,'XTZ125/Logo/logoxtz125.png','XTZ125/xtz125_2024/moto/BX5800010A06.png','XTZ125/xtz125_2024/estilo/estilo1.png','XTZ125/xtz125_2024/estilo/estilo2.png','XTZ125/xtz125_2024/estilo/estilo3.png','XTZ125/xtz125_2024/beneficios/beneficio1.jpg','XTZ125/xtz125_2024/beneficios/beneficio2.jpg','XTZ125/xtz125_2024/beneficios/beneficio3.jpg','XTZ125/xtz125_2024/beneficios/beneficio4.jpg',1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,1),(75,'BX5800010B01','XTZ125',2024,'TODO TERRENO','ON-OFF 0-149','BLA','Cross White','MOTOCICLETA XTZ125E XTZ125','MC','Supera tus límites','Su diseño, resistencia y maniobrabilidad convierten a la XTZ125 en una gran opción para usarla en todo tipo de caminos. Preparada para movilizarte ágilmente por la ciudad como para recorrer con mayor confort los terrenos difíciles, gracias a su suspensión trasera monocross. A la vez sus gráfic